/**
 * @param {number} num1
 * @param {number} num2
 * @return {number}
 */
var totalWaviness = function(num1, num2) {
    let res = 0;

    for (let i = num1; i <= num2; i++) {
        res += calcWaviness(i);
    }

    return res;
};

const calcWaviness = (num) => {
    if (num < 100) {
        return 0;
    }

    let res = 0;
    let last2 = undefined;
    let last1 = undefined;

    while (num > 0) {
        const rem = num % 10;

        if (last1 !== undefined &&
            last2 !== undefined && (
                (rem > last1 && last1 < last2) ||
                (rem < last1 && last1 > last2)
            )
        ) {
            res++;
        }

        last2 = last1;
        last1 = rem;
        num = Math.floor(num / 10);
    }

    return res;
};
